import{_ as l,H as t,f as a,i as e}from"./chunks/framework.eFU6Tutu.js";const r="/assets/green_smoothie.CDDoeGD2.jpg",o="/assets/pumpkin_soup.ooDK54pW.jpg",d="/assets/chicken_salad.tPGPfcaK.jpg",f=JSON.parse('{"title":"Готовые идеи рецептов с микрозеленью","description":"","frontmatter":{},"headers":[],"relativePath":"recipes/microgreens.md","filePath":"recipes/microgreens.md"}'),h={name:"recipes/microgreens.md"};function s(n,i,c,p,u,b){return t(),a("div",null,[...i[0]||(i[0]=[e('<h1 id="готовые-идеи-рецептов-с-микрозеленью" tabindex="-1">Готовые идеи рецептов с микрозеленью <a class="header-anchor" href="#готовые-идеи-рецептов-с-микрозеленью" aria-label="Permalink to &quot;Готовые идеи рецептов с микрозеленью&quot;">​</a></h1><h2 id="зеленыи-смузи-«будильник»" tabindex="-1">Зеленый смузи «Будильник» <a class="header-anchor" href="#зеленыи-смузи-«будильник»" aria-label="Permalink to &quot;Зеленый смузи «Будильник»&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;"><div><h3 id="ингредиенты-на-1-порцию" tabindex="-1">Ингредиенты (на 1 порцию) <a class="header-anchor" href="#ингредиенты-на-1-порцию" aria-label="Permalink to &quot;Ингредиенты (на 1 порцию)&quot;">​</a></h3><ul><li>Микрозелень брокколи — 1 горсть</li><li>Шпинат — 1 горсть</li><li>Яблоко зеленое — 1 шт</li><li>Огурец — 1/2 шт</li><li>Сок лайма — 1/2 шт</li><li>Вода или зеленый чай — 1 стакан</li><li>Семена чиа — 1 ст. ложка</li></ul></div><div><p><img src="'+r+'" alt="Зеленый смузи"></p></div></div><h3 id="калорииность-состава-в-однои-порции" tabindex="-1">Калорийность состава в одной порции <a class="header-anchor" href="#калорииность-состава-в-однои-порции" aria-label="Permalink to &quot;Калорийность состава в одной порции&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>4 г</td><td>5 г</td><td>25 г</td><td>150</td></tr></tbody></table><h3 id="приготовление" tabindex="-1">Приготовление <a class="header-anchor" href="#приготовление" aria-label="Permalink to &quot;Приготовление&quot;">​</a></h3><p>Общее время приготовления: 10 мин</p><ol><li>Яблоко и огурец вымойте, нарежьте кубиками.</li><li>Сложите все ингредиенты в блендер: микрозелень брокколи, шпинат, яблоко, огурец, сок лайма, семена чиа.</li><li>Залейте водой или охлаждённым зелёным чаем.</li><li>Взбивайте до однородной консистенции.</li><li>Подавайте сразу после приготовления.</li></ol><h2 id="тыквенныи-крем-суп-с-беконом-луком-фри-и-микрозеленью" tabindex="-1">Тыквенный крем-суп с беконом, луком фри и микрозеленью <a class="header-anchor" href="#тыквенныи-крем-суп-с-беконом-луком-фри-и-микрозеленью" aria-label="Permalink to &quot;Тыквенный крем-суп с беконом, луком фри и микрозеленью&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;"><div><h3 id="ингредиенты-на-2-порции" tabindex="-1">Ингредиенты (на 2 порции) <a class="header-anchor" href="#ингредиенты-на-2-порции" aria-label="Permalink to &quot;Ингредиенты (на 2 порции)&quot;">​</a></h3><ul><li>Тыква — 500 г</li><li>Вода — 750 мл</li><li>Лук репчатый — 1 шт.</li><li>Сливки 20% — 50 мл</li><li>Бекон — 4 шт.</li><li>Микрозелень гороха — 1 горсть</li><li>Оливковое масло — 2 ст. ложки</li><li>Чеснок — 2 зубчика</li><li>Имбирь (корень) — 20 г</li><li>Карри — 1 ч. ложка</li><li>Соль, перец — по вкусу</li></ul><p><strong>Для лука фри:</strong></p><ul><li>Лук репчатый — 1 шт.</li><li>Мука — для панировки</li><li>Растительное масло — для жарки</li></ul></div><div><p><img src="'+o+'" alt="Тыквенный крем-суп"></p></div></div><h3 id="пищевая-ценность-на-1-порцию" tabindex="-1">Пищевая ценность (на 1 порцию) <a class="header-anchor" href="#пищевая-ценность-на-1-порцию" aria-label="Permalink to &quot;Пищевая ценность (на 1 порцию)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>20 г</td><td>50 г</td><td>29 г</td><td>611</td></tr></tbody></table><h3 id="приготовление-1" tabindex="-1">Приготовление <a class="header-anchor" href="#приготовление-1" aria-label="Permalink to &quot;Приготовление&quot;">​</a></h3><p>Общее время приготовления: 50 мин</p><ol><li>Лук и чеснок измельчите, имбирь натрите на мелкой тёрке, тыкву нарежьте кубиками.</li><li>В кастрюле с толстым дном разогрейте масло, обжарьте лук с чесноком до золотистого цвета.</li><li>Добавьте имбирь и тыкву, томите 5 минут.</li><li>Влейте воду, добавьте карри, варите 20–25 минут до мягкости тыквы.</li><li>Измельчите суп блендером до состояния пюре. Посолите и поперчите.</li><li>Влейте тёплые сливки, перемешайте и доведите до кипения.</li><li>Бекон обжарьте до хруста, выложите на бумажное полотенце.</li><li>Для лука фри: нарежьте лук кольцами, обваляйте в муке с солью, обжарьте в раскалённом масле 10–15 минут до золотистого цвета.</li><li>Разлейте суп по тарелкам, украсьте беконом, луком фри и микрозеленью.</li></ol><blockquote><p><strong>Совет:</strong> Готовый суп можно хранить в холодильнике до 3 дней. Перед подачей разогревайте, но не кипятите.</p></blockquote><h2 id="салат-с-куринои-грудкои-ореховым-соусом-и-микрозеленью" tabindex="-1">Салат с куриной грудкой, ореховым соусом и микрозеленью <a class="header-anchor" href="#салат-с-куринои-грудкои-ореховым-соусом-и-микрозеленью" aria-label="Permalink to &quot;Салат с куриной грудкой, ореховым соусом и микрозеленью&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;"><div><h3 id="ингредиенты-на-4-порции" tabindex="-1">Ингредиенты (на 4 порции) <a class="header-anchor" href="#ингредиенты-на-4-порции" aria-label="Permalink to &quot;Ингредиенты (на 4 порции)&quot;">​</a></h3><ul><li>Филе куриной грудки — 500 г</li><li>Перец болгарский — 1 шт.</li><li>Огурец свежий — 1 шт.</li><li>Шпинат свежий — 100 г</li><li>Микрозелень кресс-салата — 1 горсть</li><li>Растительное масло — 2 ст. ложки</li><li>Соль, перец — по вкусу</li></ul><p><strong>Для орехового соуса:</strong></p><ul><li>Арахис жареный — 100 г</li><li>Вода — 100 мл</li><li>Кунжутное масло — 3 ст. ложки</li><li>Соевый соус — 2 ст. ложки</li><li>Яблочный уксус — 1 ст. ложка</li><li>Кунжут — 2 щепотки</li></ul></div><div><p><img src="'+d+'" alt="Салат с курицей и микрозеленью"></p></div></div><h3 id="пищевая-ценность-на-1-порцию-1" tabindex="-1">Пищевая ценность (на 1 порцию) <a class="header-anchor" href="#пищевая-ценность-на-1-порцию-1" aria-label="Permalink to &quot;Пищевая ценность (на 1 порцию)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>40 г</td><td>37 г</td><td>9 г</td><td>516</td></tr></tbody></table><h3 id="приготовление-2" tabindex="-1">Приготовление <a class="header-anchor" href="#приготовление-2" aria-label="Permalink to &quot;Приготовление&quot;">​</a></h3><p>Общее время приготовления: 30 мин</p><ol><li>Куриную грудку натрите солью и перцем, оставьте на 10–15 минут.</li><li>Разогрейте масло на сковороде, обжарьте грудку до румяной корочки с обеих сторон.</li><li>Остудите мясо и нарежьте поперёк волокон на тонкие ломтики.</li><li>Огурец нарежьте слайсами (овощечисткой), болгарский перец — брусочками.</li><li><strong>Для соуса:</strong> измельчите арахис в кофемолке или ступке. Переложите в сотейник, залейте водой, нагрейте до кипения, варите 1 минуту, помешивая. Снимите с огня, добавьте кунжутное масло, соевый соус и уксус, перемешайте.</li><li>В миске соедините курицу, овощи и шпинат. Заправьте соусом.</li><li>Украсьте микрозеленью кресс-салата.</li></ol><blockquote><p><strong>Совет:</strong> Подавайте салат сразу после приготовления — микрозелень и овощи сохранят хруст. Соус можно приготовить заранее и хранить в холодильнике до 2 дней.</p></blockquote><h2 id="другие-рецепты-с-зеленью" tabindex="-1">Другие рецепты с зеленью: <a class="header-anchor" href="#другие-рецепты-с-зеленью" aria-label="Permalink to &quot;Другие рецепты с зеленью:&quot;">​</a></h2><ul><li><a href="/recipes/mint.html">Мята</a></li><li><a href="/recipes/basil.html">Базилик</a></li></ul>',26)])])}const q=l(h,[["render",s]]);export{f as __pageData,q as default};
